    position relative;
}

.aplus-v2 .premium-aplus-module-12 .aplus-image-carousel-container {
    /* Match the aspect ratio of the desktop image uploaded via the editor (1464px x 600px) */
    padding-top calc(600 / 1464 * 100%); /* ~40.983% */
