       so we set all lists to the primary list style (numbers). */
    .aplus-brand-story-card ol li {
        list-style decimal;
    }

    /* Top level containers */
    .aplus-module .apm-brand-story-hero {
      -moz-box-sizing border-box;
      -webkit-box-sizing border-box;
